mapper.select:
SELECT id, reim_no AS reimNo, reim_status AS reimStatus, reimbursement_title AS reimbursementTitle, business_trip_reason AS businessTripReason, reimburser_id AS reimburserId, reimburser_no AS reimburserNo, reimburser_name AS reimburserName, reim_department_id AS reimDepartmentId, reim_department_no AS reimDepartmentNo, reim_department_name AS reimDepartmentName, reim_company_id AS reimCompanyId, reim_company_no AS reimCompanyNo, reim_company_name AS reimCompanyName, business_type_id AS businessTypeId, business_type_no AS businessTypeNo, business_type_name AS businessTypeName, CAST(subsidy_total AS DECIMAL(10,2)) AS subsidyTotal, CAST(meal_allowance AS DECIMAL(10,2)) AS mealAllowance, CAST(transportation_allowance AS DECIMAL(10,2)) AS transportationAllowance, CAST(phone_allowance AS DECIMAL(10,2)) AS phoneAllowance, remarks, create_user_id AS createUserId, create_user_no AS createUserNo, create_user_name AS createUserName, creation_time AS creationTime, update_user_id AS updateUserId, update_user_name AS updateUserName, update_time AS updateTime FROM fk_reim_main WHERE del_flag = 0
AND reim_no LIKE CONCAT('%', #{req.reimNo}, '%')
AND reimbursement_title LIKE CONCAT('%', #{req.reimbursementTitle}, '%')
AND business_trip_reason LIKE CONCAT('%', #{req.businessTripReason}, '%')
AND reim_company_id = #{req.reimCompanyId}
AND reim_department_id = #{req.reimDepartmentId}
AND reimburser_id = #{req.reimburserId}
AND business_type_id = #{req.businessTypeId}
ORDER BY creation_time DESC
